create table dirkspzm32.pps_plan_auftrag_ag (
    sid                   varchar2(2 char) not null enable,
    firma_nr              number(6, 0) not null enable,
    plan_auf_ag_id        number(*, 0) not null enable,
    plan_auf_id           number(*, 0) not null enable,
    vorgang               number(*, 0) not null enable,
    pos_nr                number(*, 0) not null enable,
    ag_upos               number(*, 0) default 1 not null enable,
    ag_name1              varchar2(255 char) not null enable,
    ag_name2              varchar2(255 char),
    ag_text1              varchar2(255 char),
    ag_text2              varchar2(255 char),
    ag_text3              varchar2(255 char),
    res_id                number(*, 0),
    soll_menge            number(*, 3) not null enable,
    soll_zeit_ruest       number(*, 12) default 0 not null enable,
    soll_zeit_prod        number(*, 12) default 0 not null enable,
    soll_zeit_stoer       number(*, 12) default 0 not null enable,
    soll_zeit_p_einh      number(*, 12) default 0 not null enable,
    prod_params           varchar2(4000 char),
    quitt_gruppe_ag       number(*, 5),
    termin_start_gepl     date,
    termin_ende_gepl      date,
    satzart               varchar2(2 char) not null enable,
    nio_res_id            number(*, 0),
    vorgangsqualifikation varchar2(50 char),
    created_date          date default sysdate not null enable,
    created_login_id      number(*, 0) default - 1 not null enable,
    last_change_date      date,
    last_change_login_id  number(*, 0)
);

alter table dirkspzm32.pps_plan_auftrag_ag
    add constraint pk_pps_plan_auftrag_ag
        primary key ( plan_auf_ag_id,
                      firma_nr,
                      sid )
            using index enable;


